import React, { useState, useEffect } from "react";
import FAWInput from "../../../../component-widget/FAWInput";
import FAWDropdown from "../../../../component-widget/FAWDropdown";
import FAWCheckbox from "../../../../component-widget/FAWCheckbox";
import EditorShell from "./shared/EditorShell";
import BaseQuestionFields from "./shared/BaseQuestionFields";
import EditorSection from "./shared/EditorSection";
import FAWFlagSettings from "./shared/FAWFlagSettings";
import FAWAddPrefill from "./shared/FAWAddPrefill";
import FAWCloningOptions from "./shared/FAWCloningOptions";
import FAWToast from "../../../../component-widget/FAWToast";

export default function QueTextBoxItemEditor({ 
  data, 
  onClose, 
  onSave, 
  saveRef, 
  isDefaultLanguage = true,
  availableFormFields = [],
  availableRefDomains = [],
  isDeployed = false,
  isEditMode = false,
  isSubForm = false
}) {
  const [item, setItem] = useState(
    data || {
      name: "",
      required: false,
      validationMessage: "",
      horizontalLine: false,
      text: "",
      textMode: "SingleLine",
      visibleCols: "20",
      visibleRows: "3",
      readOnly: false,
      formatOptions: "",
      maxChars: 4000,
      numericMask: "",
      minValue: "",
      maxValue: "",
      confirmationText: "",
      matchingInput: "",
      formatOptionsList: [],
      matchingInputOptions: [],
      prefillDependency: "",
      cloningOptions: {},
      flagSettings: {},
      prefillSettings: {},
    }
  );

  const [errors, setErrors] = useState({});
  const [toast, setToast] = useState({ open: false, message: '', type: 'info', duration: 3000 });
  // Add propertyType state (assume from data or default)
  const [propertyType, setPropertyType] = useState(data?.propertyType || 'String');
  // Track if user has manually edited the name
  const [userEditedName, setUserEditedName] = useState(null);

  useEffect(() => {
    if (data) {
      setItem(prev => {
        // If user has edited the name, preserve it and don't override with data
        if (userEditedName !== null && userEditedName !== data.name) {
          return { ...prev, ...data, name: userEditedName };
        }

        // If the data contains a genQuest code but the current item has a different name,
        // don't override the current name (user might have edited it)
        if (data.name && data.name.startsWith('genQuest') && prev.name && !prev.name.startsWith('genQuest')) {
          return prev;
        }

        // Only update if the data has actually changed
        if (JSON.stringify(prev) !== JSON.stringify({ ...prev, ...data })) {
          return { ...prev, ...data };
        }
        return prev; // No change needed
      });
    }
  }, [data, userEditedName]);

  const handleTextModeChange = (newTextMode) => {
    let newVisibleRows = item.visibleRows;
    let newFormatOptions = item.formatOptions;

    if (newTextMode === "MultiLine") {
      newVisibleRows = 3;
    } else if (newTextMode === "SingleLine" || newTextMode === "Date") {
      newVisibleRows = 1;
    }
    if (newTextMode === "Date") {
      newFormatOptions = '';
    }

    setItem(prev => ({
      ...prev,
      textMode: newTextMode,
      visibleRows: newVisibleRows,
      formatOptions: newFormatOptions
    }));
  };

  const validateField = (field, value) => {
    const newErrors = { ...errors };
    
    const isEmpty = (val) => {
      if (val === null || val === undefined) return true;
      if (typeof val === 'string') return val.trim() === '';
      if (typeof val === 'number') return false;
      return String(val).trim() === '';
    };
    
    const safeString = (val) => {
      if (val === null || val === undefined) return '';
      return String(val);
    };
    
    switch (field) {
      case 'visibleCols':
        if (isEmpty(value)) {
          newErrors.visibleCols = 'Visible Columns cannot be left empty';
        } else if (!/^\d+$/.test(safeString(value))) {
          newErrors.visibleCols = 'Visible Columns must be a number';
        } else {
          delete newErrors.visibleCols;
        }
        break;
        
      case 'visibleRows':
        if (isEmpty(value)) {
          newErrors.visibleRows = 'Visible Rows cannot be left empty';
        } else if (!/^\d+$/.test(safeString(value))) {
          newErrors.visibleRows = 'Visible Rows must be a number';
        } else {
          delete newErrors.visibleRows;
        }
        break;
        
      case 'maxChars':
        if (isEmpty(value)) {
          newErrors.maxChars = 'No. of characters cannot be left empty';
        } else if (!/^\d+$/.test(safeString(value))) {
          newErrors.maxChars = 'No. of characters must be a number';
        } else if (parseInt(value) > 4000) {
          newErrors.maxChars = 'Maximum no. of characters allowed are 4000';
        } else if (parseInt(value) < 0) {
          newErrors.maxChars = 'No. of characters must be a positive number';
        } else {
          delete newErrors.maxChars;
        }
        break;
        
      case 'numericMask':
        // Mask field is not shown in UI when Format = Numeric (legacy behavior)
        // Only validate format if value is provided
        if (value && !/^[-+]?([9]+|[9]+[.][9]+)$/.test(safeString(value))) {
          newErrors.numericMask = 'Mask will only accept -, +, 9 and .(period) and should be in the correct format. Ex: 999, -999.9';
        } else {
          delete newErrors.numericMask;
        }
        break;
        
      case 'minValue':
        if (value && !/^\d+$/.test(safeString(value))) {
          newErrors.minValue = 'Minimum value must be a number';
        } else {
          delete newErrors.minValue;
        }
        break;
        
      case 'maxValue':
        if (value && !/^\d+$/.test(safeString(value))) {
          newErrors.maxValue = 'Maximum value must be a number';
        } else {
          delete newErrors.maxValue;
        }
        break;
        
      default:
        break;
    }
    
    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleChange = (field, value) => {
    setItem(prev => ({ ...prev, [field]: value }));
    validateField(field, value);
  };

  const handleNumberChange = (value, field, min = 0, max = Infinity, required = false) => {
    // Always update the field value to allow typing
    setItem(prev => ({ ...prev, [field]: value }));
    
    // Then validate and set errors
    const newErrors = { ...errors };
    let isValid = true;

    // Allow empty values if not required
    if (value === '') {
      if (required) {
        newErrors[field] = `${field.charAt(0).toUpperCase() + field.slice(1)} cannot be left empty`;
        isValid = false;
      } else {
        delete newErrors[field];
      }
    } else if (!/^\d+$/.test(value)) {
      newErrors[field] = `${field.charAt(0).toUpperCase() + field.slice(1)} must be a number`;
      isValid = false;
    } else if (parseInt(value) < min || parseInt(value) > max) {
      newErrors[field] = `Value must be between ${min} and ${max}`;
      isValid = false;
    } else {
      delete newErrors[field];
    }

    setErrors(newErrors);
  };

  const handleSave = () => {
    // Prevent save if version is deployed
    if (isDeployed) {
      setToast({ open: true, message: "You cannot save this item since it is a part of a currently active version", type: 'error', duration: 5000 });
      return;
    }

    if (item.prefillSettings?.prefillAnswer && !item.prefillSettings.prefillFieldFrom) {
      setToast({ open: true, message: "When you have the Prefill Answer field checked, you must select a Prefill Field from the dropdown.", type: 'error', duration: 5000 });
      return;
    }
    // Validate all relevant fields (only if they are visible)
    const fieldsToValidate = [];
    
    // Only validate visibleCols and visibleRows if format section is visible
    if (item.textMode !== 'Date') {
      fieldsToValidate.push('visibleCols', 'visibleRows');
      
      // Only validate format-specific fields if format section is visible
      if (item.formatOptions === 'Alphabet' || item.formatOptions === 'AlphaNumeric') {
        fieldsToValidate.push('maxChars');
      }
      // Note: When Format = Numeric, Mask/MinValue/MaxValue fields are hidden in UI (legacy behavior)
      // so we don't validate them
    }
    
    let isValid = true;
    fieldsToValidate.forEach(field => {
      if (!validateField(field, item[field])) {
        isValid = false;
      }
    });

    if (!isValid) {
      setToast({ open: true, message: 'Please fix validation errors before saving.', type: 'error', duration: 5000 });
      return;
    }

    onSave && onSave(item);

  };

  const getFormatOptions = () => {
    return (item.formatOptionsList && item.formatOptionsList.length
      ? item.formatOptionsList
      : [
          { label: "None", value: "None" },
          { label: "Alphabet", value: "Alphabet" },
          { label: "Alphanumeric", value: "AlphaNumeric" },
          { label: "Confirm", value: "Confirm" },
          { label: "Email", value: "Email" },
          { label: "Match Input", value: "MatchInput" },
          { label: "Numeric", value: "Numeric" },
          { label: "Percentage", value: "Percent" },
          { label: "Phone", value: "Phone" },
        ]
    ).map(rc => ({ label: rc.Meaning || rc.label, value: rc.Code || rc.value }));
  };

  const handleFormatChange = (newFormat) => {
    let updates = { formatOptions: newFormat };

    if (newFormat !== "Alphabet" && newFormat !== "AlphaNumeric") {
      updates.maxChars = 4000;  // Legacy default
    }
    if (newFormat !== "Numeric") {
      updates.numericMask = '';  // Legacy empty
      updates.minValue = '';
      updates.maxValue = '';
    }
    if (newFormat !== "Confirm") {
      updates.confirmationText = '';  // Legacy empty
    }
    if (newFormat !== "Matching") {
      updates.matchingInput = '';  // Legacy empty
    }

    setItem(prev => ({ ...prev, ...updates }));
  };

  const isFormatSectionVisible = item.textMode !== "Date";

  // Add useEffect for propertyType condition
  useEffect(() => {
    if (propertyType === 'Int32') {
      setItem(prev => ({ ...prev, formatOptions: 'Numeric' }));
      // Disable format dropdown (add disabled prop in JSX)
    }
  }, [propertyType]);

  const handleNameChange = (newItem) => {
    
    // Check if this is a name field change (user editing the name field)
    const isNameFieldChange = newItem.name !== item.name;
    
    // If user has edited the name AND this is not a name field change (e.g., CKEditor change),
    // then preserve the user-edited name
    if (userEditedName !== null && !isNameFieldChange && newItem.name !== userEditedName) {
      newItem.name = userEditedName;
    }
    
    // Always preserve user-edited name if it exists and the new name is a genQuest code
    if (userEditedName !== null && newItem.name && newItem.name.startsWith('genQuest')) {
      newItem.name = userEditedName;
    }
    
    setItem(newItem);
    
    // Track that user has manually edited the name
    // Only set userEditedName if the new name is different from the original data name
    // AND it's not a genQuest code (to prevent genQuest codes from being treated as user edits)
    if (newItem.name !== data?.name && !newItem.name.startsWith('genQuest')) {
      setUserEditedName(newItem.name);
    } 
  };

  return (
    <EditorShell onSave={handleSave} onClose={onClose} saveRef={saveRef}>
      <BaseQuestionFields 
        item={item} 
        onChange={handleNameChange} 
        isDefaultLanguage={isDefaultLanguage} 
        availableRefDomains={availableRefDomains} 
        isDeployed={isDeployed}
        questionType="TextBoxItemType"
      />

      <EditorSection title="Textbox Options">
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
          <FAWDropdown
            label="Text Mode"
            value={item.textMode}
            options={[
              { label: "Single Line", value: "SingleLine" },
              { label: "Multi Line", value: "MultiLine" },
              { label: "Date", value: "Date" },
            ]}
            onChange={option => handleTextModeChange(option.value)}
            disabled={isDeployed && isEditMode}
            fullWidth
          />
          <div style={{ display: "flex", alignItems: "center", marginTop: 24 }}>
            <FAWCheckbox 
              label="Read Only" 
              checked={item.readOnly} 
              onChange={e=>handleChange("readOnly", e.target.checked)}
              disabled={isDeployed && isEditMode} 
            />
          </div>
        </div>
        
        {item.textMode !== 'Date' && (
          <>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 16, marginBottom: 16 }}>
              <FAWInput 
                label="Visible Columns" 
                value={item.visibleCols} 
                onChange={(e) => handleNumberChange(e.target.value, 'visibleCols', 1, 999, true)} 
                disabled={isDeployed && isEditMode}
                helperText={errors.visibleCols}
                error={!!errors.visibleCols}
                fullWidth 
              />
              <FAWInput 
                label="Visible Rows" 
                value={item.visibleRows} 
                onChange={(e) => handleNumberChange(e.target.value, 'visibleRows', 1, 99, true)} 
                disabled={item.textMode !== "MultiLine" || (isDeployed && isEditMode)}
                helperText={errors.visibleRows}
                error={!!errors.visibleRows}
                fullWidth 
              />
            </div>
          </>
        )}
      </EditorSection>

      {isFormatSectionVisible && (
        <EditorSection title="">
          <FAWDropdown
            label="Format"
            value={item.formatOptions}
            options={getFormatOptions()}
            onChange={opt => handleFormatChange(opt?.value || "None")}
            fullWidth
            disabled={propertyType === 'Int32' || item.textMode === 'Date' || isDeployed}
          />
          
          {["Alphabet", "AlphaNumeric"].includes(item.formatOptions) && (
            <FAWInput 
              label="Maximum no. of characters" 
              type="number" 
              value={item.maxChars} 
              onChange={(e) => handleNumberChange(e.target.value, 'maxChars', 0, 4000, true)}
              helperText={errors.maxChars}
              error={!!errors.maxChars}
              disabled={isDeployed}
              fullWidth 
            />
          )}
          
          {/* Note: When Format = Numeric, Mask/MinValue/MaxValue fields are hidden (legacy behavior) */}
          
          {item.formatOptions === "Confirm" && (
            <FAWInput 
              label="Confirmation Text" 
              value={item.confirmationText} 
              onChange={e=>handleChange("confirmationText", e.target.value)} 
              fullWidth 
            />
          )}
          
          {item.formatOptions === "MatchInput" && (
            <FAWDropdown 
              label="Matching Input" 
              value={item.matchingInput} 
              options={[
                { label: "--Select--", value: "0" },
                ...availableFormFields
                  .filter(field => field.type === "TextBox") // Only TextBox items like legacy
                  .map(field => ({ 
                    label: field.value || field.Value, // Show field name (addr2, bankRefContact1, etc.)
                    value: field.value || field.Value 
                  }))
              ]} 
              onChange={opt=>handleChange("matchingInput", opt?.value || "0")} 
              disabled={isDeployed}
              fullWidth 
            />
          )}
        </EditorSection>
      )}



      <div style={{ display: 'none' }}>
        <FAWFlagSettings 
          data={item.flagSettings} 
          onChange={(data) => handleChange("flagSettings", data)}
          availableFlags={[]}
          isDeployed={isDeployed}
        />
      </div>
      
      {isDefaultLanguage && !isSubForm && availableFormFields.length > 0 && (
        <EditorSection title="Prefill Options">
          <FAWAddPrefill 
            data={item.prefillSettings} 
            onChange={(data) => handleChange("prefillSettings", data)}
            availablePrefillFields={availableFormFields}
            isDeployed={isDeployed}
          />
        </EditorSection>
      )}
      
      <FAWCloningOptions 
        data={item.cloningOptions} 
        onChange={(data) => handleChange("cloningOptions", data)}
        isDeployed={isDeployed}
      />
      <FAWToast 
        open={toast.open} 
        message={toast.message} 
        type={toast.type} 
        duration={toast.duration} 
        onClose={() => setToast({ open: false, message: '', type: 'info' })}
        position="bottom-right"
      />
    </EditorShell>
  );
}



