import React, { useState, useEffect } from "react";
import FAWButton from "../../../../../component-widget/FAWButton";
import EditorSection from "./EditorSection";
import "../../controlSearch.css";

export default function FAWFlagSettings({ 
  data = {}, 
  onChange,
  availableFlags = [],
  thresholdValue = "",
  compareThresholds = false,
  expectedAnswers = [],
  unexpectedAnswers = [],
  isDeployed = false
}) {
  const [localData, setLocalData] = useState({
    compareThresholds: compareThresholds,
    thresholdValue: thresholdValue,
    expectedAnswers: expectedAnswers,
    unexpectedAnswers: unexpectedAnswers
  });
  
  const [selectedExpected, setSelectedExpected] = useState([]);
  const [selectedUnexpected, setSelectedUnexpected] = useState([]);

  useEffect(() => {
    // If no data exists or arrays are empty, initialize based on FlagAsConflict property like ASPX does
    const hasNoExpectedAnswers = !data.expectedAnswers || data.expectedAnswers.length === 0;
    const hasNoUnexpectedAnswers = !data.unexpectedAnswers || data.unexpectedAnswers.length === 0;
    
    if (hasNoExpectedAnswers && hasNoUnexpectedAnswers && availableFlags.length > 0) {
      const expectedValues = [];
      const unexpectedValues = [];
      
      // Check each flag's FlagAsConflict property to determine placement
      availableFlags.forEach(flag => {
        const value = flag.value || flag.id || String(flag);
        if (flag.FlagAsConflict === true) {
          unexpectedValues.push(value);
        } else {
          expectedValues.push(value);
        }
      });
      
      setLocalData({
        compareThresholds: data.compareThresholds || false,
        thresholdValue: data.thresholdValue || "",
        expectedAnswers: expectedValues,
        unexpectedAnswers: unexpectedValues
      });
    } else {
      setLocalData({
        compareThresholds: data.compareThresholds || false,
        thresholdValue: data.thresholdValue || "",
        expectedAnswers: data.expectedAnswers || [],
        unexpectedAnswers: data.unexpectedAnswers || []
      });
    }
    // Clear selections when data changes
    setSelectedExpected([]);
    setSelectedUnexpected([]);
  }, [data, availableFlags]);

  const handleChange = (field, value) => {
    const newData = { ...localData, [field]: value };
    setLocalData(newData);
    onChange?.(newData);
  };

  const handleMoveToRight = () => {
    // Move selected items from Expected to Unexpected
    if (selectedExpected.length === 0) return;
    
    const newExpected = localData.expectedAnswers.filter(item => !selectedExpected.includes(item));
    const newUnexpected = [...localData.unexpectedAnswers, ...selectedExpected];
    
    setLocalData(prev => ({
      ...prev,
      expectedAnswers: newExpected,
      unexpectedAnswers: newUnexpected
    }));
    
    setSelectedExpected([]); // Clear selection after move
    
    onChange?.({
      ...localData,
      expectedAnswers: newExpected,
      unexpectedAnswers: newUnexpected
    });
  };

  const handleMoveToLeft = () => {
    // Move selected items from Unexpected to Expected
    if (selectedUnexpected.length === 0) return;
    
    const newUnexpected = localData.unexpectedAnswers.filter(item => !selectedUnexpected.includes(item));
    const newExpected = [...localData.expectedAnswers, ...selectedUnexpected];
    
    setLocalData(prev => ({
      ...prev,
      expectedAnswers: newExpected,
      unexpectedAnswers: newUnexpected
    }));
    
    setSelectedUnexpected([]); // Clear selection after move
    
    onChange?.({
      ...localData,
      expectedAnswers: newExpected,
      unexpectedAnswers: newUnexpected
    });
  };

  return (
    <EditorSection title="Flag Settings">
      <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr auto 1fr", gap: 16, alignItems: "start" }}>
          <div>
            <div style={{ fontWeight: "bold", marginBottom: 8 }}>Expected Answer</div>
            <select
              multiple
              className="faw-flag-select"
              onChange={(e) => {
                const selectedValues = Array.from(e.target.selectedOptions, option => option.value);
                setSelectedExpected(selectedValues);
              }}
              style={{ 
                minHeight: 120, 
                width: "100%", 
                padding: 8,
                border: "1px solid #ccc",
                borderRadius: 4,
                fontSize: 14,
                backgroundColor: isDeployed ? "#f5f5f5" : "white"
              }}
              disabled={isDeployed}
            >
              {localData.expectedAnswers.map(value => {
                const flag = availableFlags.find(f => (f.value || f.id || String(f)) === value);
                return (
                  <option key={value} value={value}>
                    {flag ? (flag.text || flag.label || String(flag)) : value}
                  </option>
                );
              })}
            </select>
          </div>

          <div style={{ display: "flex", flexDirection: "column", gap: 8, justifyContent: "center", paddingTop: 32 }}>
            <FAWButton
              variant="outlined"
              onClick={handleMoveToRight}
              disabled={selectedExpected.length === 0}
              sx={{ minWidth: 40 }}
            >
              →
            </FAWButton>
            <FAWButton
              variant="outlined"
              onClick={handleMoveToLeft}
              disabled={selectedUnexpected.length === 0}
              sx={{ minWidth: 40 }}
            >
              ←
            </FAWButton>
          </div>

          <div>
            <div style={{ fontWeight: "bold", marginBottom: 8 }}>Unexpected Answer</div>
            <select
              multiple
              className="faw-flag-select"
              onChange={(e) => {
                const selectedValues = Array.from(e.target.selectedOptions, option => option.value);
                setSelectedUnexpected(selectedValues);
              }}
              style={{ 
                minHeight: 120, 
                width: "100%", 
                padding: 8,
                border: "1px solid #ccc",
                borderRadius: 4,
                fontSize: 14,
                backgroundColor: isDeployed ? "#f5f5f5" : "white"
              }}
              disabled={isDeployed}
            >
              {localData.unexpectedAnswers.map(value => {
                const flag = availableFlags.find(f => (f.value || f.id || String(f)) === value);
                return (
                  <option key={value} value={value}>
                    {flag ? (flag.text || flag.label || String(flag)) : value}
                  </option>
                );
              })}
            </select>
          </div>
        </div>
      </div>
    </EditorSection>
  );
}
